using Microsoft.AspNetCore.Http;
using System;
using System.IO;
namespace FileUploadService {    
    public class AvatarAndDocumentController : Controller 
    {        
        private const string UploadsFolder = "uploads";       // Define the upload folder name  
                                                                     
        [HttpPost]                                              
        public JsonResult<string> PostAvatar(IFormFile file)    
        {            
            if (file == null || file.Length == 0)                 return new JsonResult("No selected files");              // Check for no selection 
          
          var uploadsFolderPath = Path.Combine(_environemnt.ContentRootPath, UploadsFolder);   // Get the full path to save uploaded folder   
                                                                     
            if (!Directory.Exists(uploadsFolderPath))               Directory.CreateDirectory(uploadsFolderPath) ;  // Create upload directory in wwwroot/Uploads    
          
          var fileName = Guid.NewGuid() + Path.GetExtension(file.FileName);   // Generate a unique name for the uploaded files   
                                                                     
            using (var fileStream = new FileStream(Path.Combine(uploadsFolderPath,  fileName), FileMode.Create))     {            
                await file.CopyToAsync(fileStream) ;                  // Copying selected image to wwwroot/Upload folder  
           }                                                                     
            return Json("File uploaded successfully");                      // Return the success message   
        }                                                               
        
